### **7. CONFIG SCHEMA** (src/config-schema.ts)

Define configuration with Zod and build the channel config schema:

```typescript
import {
  buildChannelConfigSchema,
  DmPolicySchema,
  AllowFromListSchema,
  MarkdownConfigSchema,
} from "openclaw/plugin-sdk/channel-config-primitives";
import { z } from "openclaw/plugin-sdk/zod";

export const PulseboardAccountSchemaBase = z.object({
  name: z.string().optional(),
  enabled: z.boolean().optional(),
  apiKey: z.string().optional(),
  baseUrl: z.string().url().optional(),
  dmPolicy: DmPolicySchema.optional().default("pairing"),
  allowFrom: AllowFromListSchema,
  markdown: MarkdownConfigSchema,
}).strict();

export const PulseboardConfigSchema = PulseboardAccountSchemaBase.extend({
  accounts: z.record(z.string(), PulseboardAccountSchemaBase.optional()).optional(),
  defaultAccount: z.string().optional(),
});

export const PulseboardChannelConfigSchema = buildChannelConfigSchema(
  PulseboardConfigSchema,
  { uiHints: {} }
);
```

**Patterns:**
- Use Zod for type-safe validation
- Create base account schema, extend for full config with accounts record
- Use `z.strict()` to reject extra properties
- `DmPolicySchema`, `AllowFromListSchema`, `MarkdownConfigSchema` are built-in helpers
- Final export via `buildChannelConfigSchema()`

