### **8. CHANNEL PLUGIN DEFINITION** (src/channel.ts)

The core plugin definition using `createChatChannelPlugin` helper:

```typescript
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";

type ResolvedPulseboardAccount = {
  accountId: string;
  configured: boolean;
  apiKey: string;
  // ... other fields
};

export const pulseboardPlugin: ChannelPlugin<ResolvedPulseboardAccount> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: { /* ... */ },
      setup: pulseboardSetupAdapter,
      capabilities: {
        chatTypes: ["direct", "group"],
        media: true,
        blockStreaming: false,
      },
      config: {
        listAccountIds: listPulseboardAccountIds,
        resolveAccount: resolvePulseboardAccount,
        isConfigured: (account) => account.configured,
        describeAccount: (account) => ({
          configured: account.configured,
          extra: { baseUrl: account.baseUrl },
        }),
      },
      messaging: {
        normalizeTarget: normalizePulseboardTarget,
        targetResolver: {
          looksLikeId: (id) => /^\d+$/.test(id),
          hint: "<userId|groupId>",
        },
      },
      resolver: {
        resolveTargets: async ({ inputs, kind }) => {
          // Resolve user/group IDs
          return inputs.map(input => ({
            input,
            resolved: true,
            id: input,
            name: input,
          }));
        },
      },
    },
    security: {
      dm: {
        channelKey: "pulseboard",
        resolvePolicy: (account) => account.config.dmPolicy,
        resolveAllowFrom: (account) => account.config.allowFrom,
        normalizeEntry: (raw) => raw.trim(),
      },
    },
    pairing: {
      text: {
        idLabel: "pulseboardUserId",
        message: "You've been approved for direct messages.",
        notify: async ({ id, message }) => {
          await getPulseboardRuntime().channel.pulseboard.sendMessage(id, message);
        },
      },
    },
    threading: {
      topLevelReplyToMode: "pulseboard",
    },
    outbound: {
      base: {
        deliveryMode: "direct",
        textChunkLimit: 4000,
        resolveTarget: ({ to }) => normalizePulseboardTarget(to),
      },
      attachedResults: {
        channel: "pulseboard",
        sendText: async ({ to, text, accountId }) => {
          return await getPulseboardRuntime().channel.pulseboard.sendMessage(
            to, text, { accountId }
          );
        },
      },
    },
  });
```

**Key sections of base config:**
- `id`: Channel ID (must match package.json openclaw.channel.id)
- `setup`: Setup adapter for CLI configuration
- `capabilities`: Chat types, media support, streaming
- `config`: Account list/resolution/validation logic
- `messaging`: Target normalization and resolver
- `resolver`: Resolve free-form inputs to valid targets
- Composed with `security`, `pairing`, `threading`, `outbound` via helper

