6	export type ParsedIrcLine = {
7	  raw: string;
8	  prefix?: string;
9	  command: string;
10	  params: string[];
11	  trailing?: string;
12	};
13	
14	export type ParsedIrcPrefix = {
15	  nick?: string;
16	  user?: string;
17	  host?: string;
18	  server?: string;
19	};
