1	import type { ChannelOutboundAdapter } from "../channels/plugins/types.js";
2	
3	export type { MediaPayload, MediaPayloadInput } from "../channels/plugins/media-payload.js";
4	export { buildMediaPayload } from "../channels/plugins/media-payload.js";
5	
6	export type OutboundReplyPayload = {
7	  text?: string;
8	  mediaUrls?: string[];
9	  mediaUrl?: string;
10	  replyToId?: string;
11	};
12	
13	export type SendableOutboundReplyParts = {
14	  text: string;
15	  trimmedText: string;
16	  mediaUrls: string[];
17	  mediaCount: number;
18	  hasText: boolean;
19	  hasMedia: boolean;
20	  hasContent: boolean;
21	};
22	
23	type SendPayloadContext = Parameters<NonNullable<ChannelOutboundAdapter["sendPayload"]>>[0];
24	type SendPayloadResult = Awaited<ReturnType<NonNullable<ChannelOutboundAdapter["sendPayload"]>>>;
25	type SendPayloadAdapter = Pick<
26	  ChannelOutboundAdapter,
27	  "sendMedia" | "sendText" | "chunker" | "textChunkLimit"
28	>;
29	
30	/** Extract the supported outbound reply fields from loose tool or agent payload objects. */
31	export function normalizeOutboundReplyPayload(
32	  payload: Record<string, unknown>,
33	): OutboundReplyPayload {
34	  const text = typeof payload.text === "string" ? payload.text : undefined;
35	  const mediaUrls = Array.isArray(payload.mediaUrls)
36	    ? payload.mediaUrls.filter(
37	        (entry): entry is string => typeof entry === "string" && entry.length > 0,
38	      )
39	    : undefined;
40	  const mediaUrl = typeof payload.mediaUrl === "string" ? payload.mediaUrl : undefined;
41	  const replyToId = typeof payload.replyToId === "string" ? payload.replyToId : undefined;
42	  return {
43	    text,
44	    mediaUrls,
45	    mediaUrl,
46	    replyToId,
47	  };
48	}
49	
50	/** Wrap a deliverer so callers can hand it arbitrary payloads while channels receive normalized data. */
51	export function createNormalizedOutboundDeliverer(
52	  handler: (payload: OutboundReplyPayload) => Promise<void>,
53	): (payload: unknown) => Promise<void> {
54	  return async (payload: unknown) => {
55	    const normalized =
56	      payload && typeof payload === "object"
57	        ? normalizeOutboundReplyPayload(payload as Record<string, unknown>)
58	        : {};
59	    await handler(normalized);
60	  };
61	}
62	
63	/** Prefer multi-attachment payloads, then fall back to the legacy single-media field. */
64	export function resolveOutboundMediaUrls(payload: {
65	  mediaUrls?: string[];
66	  mediaUrl?: string;
67	}): string[] {
68	  if (payload.mediaUrls?.length) {
69	    return payload.mediaUrls;
70	  }
71	  if (payload.mediaUrl) {
72	    return [payload.mediaUrl];
73	  }
74	  return [];
75	}
76	
77	/** Resolve media URLs from a channel sendPayload context after legacy fallback normalization. */
78	export function resolvePayloadMediaUrls(payload: SendPayloadContext["payload"]): string[] {
79	  return resolveOutboundMediaUrls(payload);
80	}
81	
82	/** Count outbound media items after legacy single-media fallback normalization. */
83	export function countOutboundMedia(payload: { mediaUrls?: string[]; mediaUrl?: string }): number {
84	  return resolveOutboundMediaUrls(payload).length;
85	}
86	
87	/** Check whether an outbound payload includes any media after normalization. */
88	export function hasOutboundMedia(payload: { mediaUrls?: string[]; mediaUrl?: string }): boolean {
89	  return countOutboundMedia(payload) > 0;
90	}
91	
92	/** Check whether an outbound payload includes text, optionally trimming whitespace first. */
93	export function hasOutboundText(payload: { text?: string }, options?: { trim?: boolean }): boolean {
94	  const text = options?.trim ? payload.text?.trim() : payload.text;
95	  return Boolean(text);
96	}
97	
98	/** Check whether an outbound payload includes any sendable text or media. */
99	export function hasOutboundReplyContent(
100	  payload: { text?: string; mediaUrls?: string[]; mediaUrl?: string },
101	  options?: { trimText?: boolean },
102	): boolean {
103	  return hasOutboundText(payload, { trim: options?.trimText }) || hasOutboundMedia(payload);
104	}
105	
106	/** Normalize reply payload text/media into a trimmed, sendable shape for delivery paths. */
107	export function resolveSendableOutboundReplyParts(
108	  payload: { text?: string; mediaUrls?: string[]; mediaUrl?: string },
109	  options?: { text?: string },
110	): SendableOutboundReplyParts {
111	  const text = options?.text ?? payload.text ?? "";
112	  const trimmedText = text.trim();
113	  const mediaUrls = resolveOutboundMediaUrls(payload)
114	    .map((entry) => entry.trim())
115	    .filter(Boolean);
116	  const mediaCount = mediaUrls.length;
117	  const hasText = Boolean(trimmedText);
118	  const hasMedia = mediaCount > 0;
119	  return {
120	    text,
121	    trimmedText,
122	    mediaUrls,
123	    mediaCount,
124	    hasText,
125	    hasMedia,
126	    hasContent: hasText || hasMedia,
127	  };
128	}
129	
130	/** Preserve caller-provided chunking, but fall back to the full text when chunkers return nothing. */
131	export function resolveTextChunksWithFallback(text: string, chunks: readonly string[]): string[] {
132	  if (chunks.length > 0) {
133	    return [...chunks];
134	  }
135	  if (!text) {
136	    return [];
137	  }
138	  return [text];
139	}
140	
141	/** Send media-first payloads intact, or chunk text-only payloads through the caller's transport hooks. */
142	export async function sendPayloadWithChunkedTextAndMedia<
143	  TContext extends { payload: object },
144	  TResult,
145	>(params: {
146	  ctx: TContext;
147	  textChunkLimit?: number;
148	  chunker?: ((text: string, limit: number) => string[]) | null;
149	  sendText: (ctx: TContext & { text: string }) => Promise<TResult>;
150	  sendMedia: (ctx: TContext & { text: string; mediaUrl: string }) => Promise<TResult>;
151	  emptyResult: TResult;
152	}): Promise<TResult> {
153	  const payload = params.ctx.payload as { text?: string; mediaUrls?: string[]; mediaUrl?: string };
154	  const text = payload.text ?? "";
155	  const urls = resolveOutboundMediaUrls(payload);
156	  if (!text && urls.length === 0) {
157	    return params.emptyResult;
158	  }
159	  if (urls.length > 0) {
160	    let lastResult = await params.sendMedia({
161	      ...params.ctx,
162	      text,
163	      mediaUrl: urls[0],
164	    });
165	    for (let i = 1; i < urls.length; i++) {
166	      lastResult = await params.sendMedia({
167	        ...params.ctx,
168	        text: "",
169	        mediaUrl: urls[i],
170	      });
171	    }
172	    return lastResult;
173	  }
174	  const limit = params.textChunkLimit;
175	  const chunks = limit && params.chunker ? params.chunker(text, limit) : [text];
176	  let lastResult: TResult;
177	  for (const chunk of chunks) {
178	    lastResult = await params.sendText({ ...params.ctx, text: chunk });
179	  }
180	  return lastResult!;
181	}
182	
183	export async function sendPayloadMediaSequence<TResult>(params: {
184	  text: string;
185	  mediaUrls: readonly string[];
186	  send: (input: {
187	    text: string;
188	    mediaUrl: string;
189	    index: number;
190	    isFirst: boolean;
191	  }) => Promise<TResult>;
192	}): Promise<TResult | undefined> {
193	  let lastResult: TResult | undefined;
194	  for (let i = 0; i < params.mediaUrls.length; i += 1) {
195	    const mediaUrl = params.mediaUrls[i];
196	    if (!mediaUrl) {
197	      continue;
198	    }
199	    lastResult = await params.send({
200	      text: i === 0 ? params.text : "",
201	      mediaUrl,
202	      index: i,
203	      isFirst: i === 0,
204	    });
205	  }
206	  return lastResult;
207	}
208	
209	export async function sendPayloadMediaSequenceOrFallback<TResult>(params: {
210	  text: string;
211	  mediaUrls: readonly string[];
212	  send: (input: {
213	    text: string;
214	    mediaUrl: string;
215	    index: number;
216	    isFirst: boolean;
217	  }) => Promise<TResult>;
218	  fallbackResult: TResult;
219	  sendNoMedia?: () => Promise<TResult>;
220	}): Promise<TResult> {
221	  if (params.mediaUrls.length === 0) {
222	    return params.sendNoMedia ? await params.sendNoMedia() : params.fallbackResult;
223	  }
224	  return (await sendPayloadMediaSequence(params)) ?? params.fallbackResult;
225	}
226	
227	export async function sendPayloadMediaSequenceAndFinalize<TMediaResult, TResult>(params: {
228	  text: string;
229	  mediaUrls: readonly string[];
230	  send: (input: {
231	    text: string;
232	    mediaUrl: string;
233	    index: number;
234	    isFirst: boolean;
235	  }) => Promise<TMediaResult>;
236	  finalize: () => Promise<TResult>;
237	}): Promise<TResult> {
238	  if (params.mediaUrls.length > 0) {
239	    await sendPayloadMediaSequence(params);
240	  }
241	  return await params.finalize();
242	}
243	
244	export async function sendTextMediaPayload(params: {
245	  channel: string;
246	  ctx: SendPayloadContext;
247	  adapter: SendPayloadAdapter;
248	}): Promise<SendPayloadResult> {
249	  const text = params.ctx.payload.text ?? "";
250	  const urls = resolvePayloadMediaUrls(params.ctx.payload);
251	  if (!text && urls.length === 0) {
252	    return { channel: params.channel, messageId: "" };
253	  }
254	  if (urls.length > 0) {
255	    const lastResult = await sendPayloadMediaSequence({
256	      text,
257	      mediaUrls: urls,
258	      send: async ({ text, mediaUrl }) =>
259	        await params.adapter.sendMedia!({
260	          ...params.ctx,
261	          text,
262	          mediaUrl,
263	        }),
264	    });
265	    return lastResult ?? { channel: params.channel, messageId: "" };
266	  }
267	  const limit = params.adapter.textChunkLimit;
268	  const chunks = limit && params.adapter.chunker ? params.adapter.chunker(text, limit) : [text];
269	  let lastResult: Awaited<ReturnType<NonNullable<typeof params.adapter.sendText>>>;
270	  for (const chunk of chunks) {
271	    lastResult = await params.adapter.sendText!({ ...params.ctx, text: chunk });
272	  }
273	  return lastResult!;
274	}
275	
276	/** Detect numeric-looking target ids for channels that distinguish ids from handles. */
277	export function isNumericTargetId(raw: string): boolean {
278	  const trimmed = raw.trim();
279	  if (!trimmed) {
280	    return false;
281	  }
282	  return /^\d{3,}$/.test(trimmed);
283	}
284	
285	/** Append attachment links to plain text when the channel cannot send media inline. */
286	export function formatTextWithAttachmentLinks(
287	  text: string | undefined,
288	  mediaUrls: string[],
289	): string {
290	  const trimmedText = text?.trim() ?? "";
291	  if (!trimmedText && mediaUrls.length === 0) {
292	    return "";
293	  }
294	  const mediaBlock = mediaUrls.length
295	    ? mediaUrls.map((url) => `Attachment: ${url}`).join("\n")
296	    : "";
297	  if (!trimmedText) {
298	    return mediaBlock;
299	  }
300	  if (!mediaBlock) {
301	    return trimmedText;
302	  }
303	  return `${trimmedText}\n\n${mediaBlock}`;
304	}
305	
306	/** Send a caption with only the first media item, mirroring caption-limited channel transports. */
307	export async function sendMediaWithLeadingCaption(params: {
308	  mediaUrls: string[];
309	  caption: string;
310	  send: (payload: { mediaUrl: string; caption?: string }) => Promise<void>;
311	  onError?: (params: {
312	    error: unknown;
313	    mediaUrl: string;
314	    caption?: string;
315	    index: number;
316	    isFirst: boolean;
317	  }) => Promise<void> | void;
318	}): Promise<boolean> {
319	  if (params.mediaUrls.length === 0) {
320	    return false;
321	  }
322	
323	  for (const [index, mediaUrl] of params.mediaUrls.entries()) {
324	    const isFirst = index === 0;
325	    const caption = isFirst ? params.caption : undefined;
326	    try {
327	      await params.send({ mediaUrl, caption });
328	    } catch (error) {
329	      if (params.onError) {
330	        await params.onError({
331	          error,
332	          mediaUrl,
333	          caption,
334	          index,
335	          isFirst,
336	        });
337	        continue;
338	      }
339	      throw error;
340	    }
341	  }
342	  return true;
343	}
344	
345	export async function deliverTextOrMediaReply(params: {
346	  payload: OutboundReplyPayload;
347	  text: string;
348	  chunkText?: (text: string) => readonly string[];
349	  sendText: (text: string) => Promise<void>;
350	  sendMedia: (payload: { mediaUrl: string; caption?: string }) => Promise<void>;
351	  onMediaError?: (params: {
352	    error: unknown;
353	    mediaUrl: string;
354	    caption?: string;
355	    index: number;
356	    isFirst: boolean;
357	  }) => Promise<void> | void;
358	}): Promise<"empty" | "text" | "media"> {
359	  const { mediaUrls } = resolveSendableOutboundReplyParts(params.payload, {
360	    text: params.text,
361	  });
362	  const sentMedia = await sendMediaWithLeadingCaption({
363	    mediaUrls,
364	    caption: params.text,
365	    send: params.sendMedia,
366	    onError: params.onMediaError,
367	  });
368	  if (sentMedia) {
369	    return "media";
370	  }
371	  if (!params.text) {
372	    return "empty";
373	  }
374	  const chunks = params.chunkText ? params.chunkText(params.text) : [params.text];
375	  let sentText = false;
376	  for (const chunk of chunks) {
377	    if (!chunk) {
378	      continue;
379	    }
380	    await params.sendText(chunk);
381	    sentText = true;
382	  }
383	  return sentText ? "text" : "empty";
384	}
385	
386	export async function deliverFormattedTextWithAttachments(params: {
387	  payload: OutboundReplyPayload;
388	  send: (params: { text: string; replyToId?: string }) => Promise<void>;
389	}): Promise<boolean> {
390	  const text = formatTextWithAttachmentLinks(
391	    params.payload.text,
392	    resolveOutboundMediaUrls(params.payload),
393	  );
394	  if (!text) {
395	    return false;
396	  }
397	  await params.send({
398	    text,
399	    replyToId: params.payload.replyToId,
400	  });
401	  return true;
402	}
