import type { PulseboardInboundMessage } from "./types.js";

/** Board targets: "boards/general", "board:general", or bare "general" (group). */
const BOARD_PREFIX_RE = /^board(?:s)?[:\/]/iu;

/** User/DM targets: "@alice" or a numeric id like "12345". */
const USER_PREFIX_RE = /^(?:user|dm)[:\/]/iu;
const NUMERIC_ID_RE = /^\d+$/u;

export function isBoardTarget(target: string): boolean {
  return target.startsWith("boards/");
}

export function normalizePulseboardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  let target = trimmed;
  // Strip leading channel scheme, e.g. "pulseboard:boards/general"
  if (target.toLowerCase().startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }
  // Normalize "board:general" or "boards/general" → "boards/<name>"
  if (BOARD_PREFIX_RE.test(target)) {
    const name = target.replace(BOARD_PREFIX_RE, "").trim();
    if (!name) {
      return undefined;
    }
    return `boards/${name}`;
  }
  // Normalize "user:alice" or "dm:alice" → "@alice"
  if (USER_PREFIX_RE.test(target)) {
    const name = target.replace(USER_PREFIX_RE, "").trim();
    if (!name) {
      return undefined;
    }
    return name.startsWith("@") ? name : `@${name}`;
  }
  // Bare "@alice" handle
  if (target.startsWith("@")) {
    const handle = target.slice(1).trim();
    if (!handle) {
      return undefined;
    }
    return `@${handle}`;
  }
  // Numeric user id
  if (NUMERIC_ID_RE.test(target)) {
    return target;
  }
  return undefined;
}

export function looksLikePulseboardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  return normalizePulseboardMessagingTarget(trimmed) !== undefined;
}

export function normalizePulseboardAllowEntry(raw: string): string {
  const trimmed = raw.trim().toLowerCase();
  if (!trimmed) {
    return "";
  }
  if (trimmed === "*") {
    return "*";
  }
  // Strip scheme prefixes
  const cleaned = trimmed
    .replace(/^pulseboard:/u, "")
    .replace(/^(?:user|dm)[:\/]/u, "")
    .trim();
  if (!cleaned) {
    return "";
  }
  return cleaned.startsWith("@") ? cleaned : `@${cleaned}`;
}

export function normalizePulseboardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? []).map((entry) => normalizePulseboardAllowEntry(String(entry))).filter(Boolean);
}

export function formatPulseboardSenderId(message: PulseboardInboundMessage): string {
  const handle = message.senderHandle.trim();
  const id = message.senderId.trim();
  if (id && id !== handle) {
    return `${handle} (${id})`;
  }
  return handle;
}

export function buildPulseboardAllowlistCandidates(message: PulseboardInboundMessage): string[] {
  const handle = message.senderHandle.trim().toLowerCase();
  const id = message.senderId.trim().toLowerCase();
  const candidates = new Set<string>();
  if (handle) {
    candidates.add(handle.startsWith("@") ? handle : `@${handle}`);
  }
  if (id && id !== handle) {
    candidates.add(id);
  }
  return [...candidates];
}

export function resolvePulseboardAllowlistMatch(params: {
  allowFrom: string[];
  message: PulseboardInboundMessage;
}): { allowed: boolean; source?: string } {
  const allowFrom = new Set(
    params.allowFrom.map((entry) => entry.trim().toLowerCase()).filter(Boolean),
  );
  if (allowFrom.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const candidates = buildPulseboardAllowlistCandidates(params.message);
  for (const candidate of candidates) {
    if (allowFrom.has(candidate)) {
      return { allowed: true, source: candidate };
    }
  }
  return { allowed: false };
}

