import { normalizePulseboardAllowlist, resolvePulseboardAllowlistMatch } from "./normalize.js";
import type { PulseboardAccountConfig, PulseboardBoardConfig, PulseboardInboundMessage } from "./types.js";

export type PulseboardBoardMatch = {
  allowed: boolean;
  boardConfig?: PulseboardBoardConfig;
  wildcardConfig?: PulseboardBoardConfig;
  hasConfiguredBoards: boolean;
};

export type PulseboardBoardAccessGate = {
  allowed: boolean;
  reason: string;
};

export function resolvePulseboardBoardMatch(params: {
  boards?: Record<string, PulseboardBoardConfig>;
  target: string;
}): PulseboardBoardMatch {
  const boards = params.boards ?? {};
  const hasConfiguredBoards = Object.keys(boards).length > 0;

  // Exact match first
  const direct = boards[params.target];
  if (direct) {
    return { allowed: true, boardConfig: direct, wildcardConfig: boards["*"], hasConfiguredBoards };
  }

  // Case-insensitive fallback
  const targetLower = params.target.toLowerCase();
  const directKey = Object.keys(boards).find((key) => key.toLowerCase() === targetLower);
  if (directKey) {
    const matched = boards[directKey];
    if (matched) {
      return {
        allowed: true,
        boardConfig: matched,
        wildcardConfig: boards["*"],
        hasConfiguredBoards,
      };
    }
  }

  // Wildcard fallback
  const wildcard = boards["*"];
  if (wildcard) {
    return { allowed: true, wildcardConfig: wildcard, hasConfiguredBoards };
  }
  return { allowed: false, hasConfiguredBoards };
}

export function resolvePulseboardBoardAccessGate(params: {
  groupPolicy: PulseboardAccountConfig["groupPolicy"];
  boardMatch: PulseboardBoardMatch;
}): PulseboardBoardAccessGate {
  const policy = params.groupPolicy ?? "allowlist";
  if (policy === "disabled") {
    return { allowed: false, reason: "groupPolicy=disabled" };
  }

  if (policy === "allowlist") {
    if (!params.boardMatch.hasConfiguredBoards) {
      return { allowed: false, reason: "groupPolicy=allowlist and no boards configured" };
    }
    if (!params.boardMatch.allowed) {
      return { allowed: false, reason: "not allowlisted" };
    }
  }

  if (
    params.boardMatch.boardConfig?.enabled === false ||
    params.boardMatch.wildcardConfig?.enabled === false
  ) {
    return { allowed: false, reason: "disabled" };
  }

  return { allowed: true, reason: policy === "open" ? "open" : "allowlisted" };
}

export function resolvePulseboardRequireMention(params: {
  boardConfig?: PulseboardBoardConfig;
  wildcardConfig?: PulseboardBoardConfig;
}): boolean {
  if (params.boardConfig?.requireMention !== undefined) {
    return params.boardConfig.requireMention;
  }
  if (params.wildcardConfig?.requireMention !== undefined) {
    return params.wildcardConfig.requireMention;
  }
  return true;
}

export function resolvePulseboardMentionGate(params: {
  isGroup: boolean;
  requireMention: boolean;
  wasMentioned: boolean;
  hasControlCommand: boolean;
  allowTextCommands: boolean;
  commandAuthorized: boolean;
}): { shouldSkip: boolean; reason: string } {
  if (!params.isGroup) {
    return { shouldSkip: false, reason: "direct" };
  }
  if (!params.requireMention) {
    return { shouldSkip: false, reason: "mention-not-required" };
  }
  if (params.wasMentioned) {
    return { shouldSkip: false, reason: "mentioned" };
  }
  if (params.hasControlCommand && params.allowTextCommands && params.commandAuthorized) {
    return { shouldSkip: false, reason: "authorized-command" };
  }
  return { shouldSkip: true, reason: "missing-mention" };
}

export function resolvePulseboardGroupSenderAllowed(params: {
  groupPolicy: PulseboardAccountConfig["groupPolicy"];
  message: PulseboardInboundMessage;
  outerAllowFrom: string[];
  innerAllowFrom: string[];
}): boolean {
  const policy = params.groupPolicy ?? "allowlist";
  const inner = normalizePulseboardAllowlist(params.innerAllowFrom);
  const outer = normalizePulseboardAllowlist(params.outerAllowFrom);

  if (inner.length > 0) {
    return resolvePulseboardAllowlistMatch({ allowFrom: inner, message: params.message }).allowed;
  }
  if (outer.length > 0) {
    return resolvePulseboardAllowlistMatch({ allowFrom: outer, message: params.message }).allowed;
  }
  return policy === "open";
}

