import { resolveMarkdownTableMode } from "openclaw/plugin-sdk/config-runtime";
import { convertMarkdownTables } from "openclaw/plugin-sdk/text-runtime";
import { resolvePulseboardAccount } from "./accounts.js";
import { normalizePulseboardMessagingTarget } from "./normalize.js";
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseboardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
};

export type SendPulseboardResult = {
  messageId: string;
  target: string;
};

function makePulseboardMessageId(): string {
  return `pb-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
}

function recordPulseboardOutboundActivity(accountId: string): void {
  try {
    getPulseboardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    if (!(error instanceof Error) || error.message !== "PulseBoard runtime not initialized") {
      throw error;
    }
  }
}

function resolveTarget(to: string): string {
  const normalized = normalizePulseboardMessagingTarget(to);
  if (normalized) {
    return normalized;
  }
  throw new Error(`Invalid PulseBoard target: ${to}`);
}

/**
 * Send a message to a PulseBoard board or user.
 * Boards are addressed as "boards/<name>"; DM users as "@<handle>" or numeric id.
 */
export async function sendMessagePulseboard(
  to: string,
  text: string,
  opts: SendPulseboardOptions = {},
): Promise<SendPulseboardResult> {
  const runtime = getPulseboardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseboardAccount({
    cfg,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiToken and serverUrl in channels.pulseboard).`,
    );
  }

  const target = resolveTarget(to);
  const tableMode = resolveMarkdownTableMode({
    cfg,
    channel: "pulseboard",
    accountId: account.accountId,
  });
  const prepared = convertMarkdownTables(text.trim(), tableMode);
  const payload = opts.replyTo ? `${prepared}\n\n[reply:${opts.replyTo}]` : prepared;

  if (!payload.trim()) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  // Determine the API path based on target type
  const isBoard = target.startsWith("boards/");
  const apiPath = isBoard
    ? `/v1/boards/${encodeURIComponent(target.slice("boards/".length))}/messages`
    : `/v1/users/${encodeURIComponent(target.replace(/^@/u, ""))}/messages`;

  const url = `${account.serverUrl.replace(/\/+$/u, "")}${apiPath}`;
  const response = await fetch(url, {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${account.apiToken}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ text: payload }),
  });

  if (!response.ok) {
    throw new Error(
      `PulseBoard API error sending to ${target}: ${response.status} ${response.statusText}`,
    );
  }

  const json = (await response.json()) as { messageId?: string };
  const messageId = json.messageId ?? makePulseboardMessageId();
  recordPulseboardOutboundActivity(account.accountId);

  return { messageId, target };
}

