import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseboardAccount } from "./accounts.js";
import { isBoardTarget } from "./normalize.js";
import { handlePulseboardInbound } from "./inbound.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig, PulseboardInboundMessage } from "./types.js";

export type PulseboardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseboardInboundMessage) => void | Promise<void>;
};

/** Resolve the canonical conversation target from a raw PulseBoard event. */
export function resolvePulseboardInboundTarget(params: {
  boardPath?: string;
  senderHandle: string;
}): { isGroup: boolean; target: string } {
  if (params.boardPath) {
    return { isGroup: true, target: params.boardPath };
  }
  return { isGroup: false, target: params.senderHandle };
}

/**
 * Long-poll the PulseBoard events endpoint and dispatch inbound messages.
 * Returns a stop handle; callers should honour the abortSignal as well.
 */
export async function monitorPulseboardProvider(
  opts: PulseboardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseboardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseboardAccount({ cfg, accountId: opts.accountId });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiToken and serverUrl in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  let stopped = false;
  let cursor: string | undefined;

  const baseUrl = account.serverUrl.replace(/\/+$/u, "");

  logger.info(
    `[${account.accountId}] starting PulseBoard provider (${baseUrl})`,
  );

  async function poll(): Promise<void> {
    while (!stopped && !opts.abortSignal?.aborted) {
      try {
        const url = new URL(`${baseUrl}/v1/events/poll`);
        if (cursor) {
          url.searchParams.set("after", cursor);
        }
        url.searchParams.set("timeout", "30");

        const controller = new AbortController();
        const abortHandler = () => controller.abort();
        opts.abortSignal?.addEventListener("abort", abortHandler, { once: true });

        let response: Response;
        try {
          response = await fetch(url.toString(), {
            method: "GET",
            headers: { Authorization: `Bearer ${account.apiToken}` },
            signal: controller.signal,
          });
        } finally {
          opts.abortSignal?.removeEventListener("abort", abortHandler);
        }

        if (!response.ok) {
          logger.error(
            `[${account.accountId}] PulseBoard poll error: ${response.status} ${response.statusText}`,
          );
          // Back off on error
          await sleep(5000, opts.abortSignal);
          continue;
        }

        const body = (await response.json()) as {
          events?: PulseboardEventPayload[];
          nextCursor?: string;
        };

        if (body.nextCursor) {
          cursor = body.nextCursor;
        }

        for (const event of body.events ?? []) {
          if (stopped || opts.abortSignal?.aborted) {
            break;
          }
          await dispatchEvent(event, cfg, account.accountId);
        }
      } catch (err) {
        if (stopped || opts.abortSignal?.aborted) {
          break;
        }
        logger.error(`[${account.accountId}] PulseBoard poll failed: ${String(err)}`);
        await sleep(5000, opts.abortSignal);
      }
    }
  }

  type PulseboardEventPayload = {
    eventId: string;
    type: "message";
    boardPath?: string;
    senderHandle: string;
    senderId: string;
    text: string;
    timestamp: number;
  };

  async function dispatchEvent(
    event: PulseboardEventPayload,
    currentCfg: CoreConfig,
    accountId: string,
  ): Promise<void> {
    if (event.type !== "message") {
      return;
    }
    // Skip messages from self
    if (event.senderHandle === account.config.defaultTo) {
      return;
    }

    const inboundTarget = resolvePulseboardInboundTarget({
      boardPath: event.boardPath,
      senderHandle: event.senderHandle,
    });

    const message: PulseboardInboundMessage = {
      messageId: event.eventId,
      target: inboundTarget.target,
      senderHandle: event.senderHandle,
      senderId: event.senderId,
      text: event.text,
      timestamp: event.timestamp || Date.now(),
      isGroup: inboundTarget.isGroup,
    };

    core.channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "inbound",
      at: message.timestamp,
    });

    if (opts.onMessage) {
      await opts.onMessage(message);
      return;
    }

    await handlePulseboardInbound({
      message,
      account: resolvePulseboardAccount({ cfg: currentCfg, accountId }),
      config: currentCfg,
      runtime,
      sendReply: async (target, text) => {
        const { sendMessagePulseboard } = await import("./send.js");
        await sendMessagePulseboard(target, text, { accountId, cfg: currentCfg });
        opts.statusSink?.({ lastOutboundAt: Date.now() });
        core.channel.activity.record({
          channel: "pulseboard",
          accountId,
          direction: "outbound",
        });
      },
      statusSink: opts.statusSink,
    });
  }

  // Start polling in the background; errors are caught inside the loop.
  poll().catch((err) => {
    if (!stopped) {
      logger.error(`[${account.accountId}] PulseBoard monitor crashed: ${String(err)}`);
    }
  });

  return {
    stop: () => {
      stopped = true;
    },
  };
}

function sleep(ms: number, abortSignal?: AbortSignal): Promise<void> {
  return new Promise((resolve) => {
    if (abortSignal?.aborted) {
      resolve();
      return;
    }
    const timer = setTimeout(resolve, ms);
    abortSignal?.addEventListener("abort", () => {
      clearTimeout(timer);
      resolve();
    }, { once: true });
  });
}

